1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioOutput {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const RUNE_BLOCK_PRICE = 60;
58	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
59	  sword: 100,
60	  amulet: 60,
61	  staff: 80,
62	  potion: 40,
63	  rune: 25,
64	};
65	
66	const basePremium = (item: Item): number =>
67	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
68	
69	const isRuneBlock = (items: Item[]): boolean =>
70	  items.length === BLOCK_SIZE && items.every((it) => it.type === "rune");
71	
72	const componentsTotal = (items: Item[]): number =>
73	  isRuneBlock(items)
74	    ? RUNE_BLOCK_PRICE
75	    : items.reduce((sum, item) => sum + basePremium(item), 0);
76	
77	const quotePremium = (items: Item[]): number =>
78	  componentsTotal(items) + PROCESSING_FEE;
79	
80	export const processScenario = (scenario: Scenario): ScenarioOutput => {
81	  const step = scenario.steps[0] as QuoteStep;
82	  return { results: [{ premium: quotePremium(step.items) }] };
83	};
